 1→package dev.tuist.gradle
 2→
 3→interface GitInfoProvider {
 4→    fun branch(): String?
 5→    fun commitSha(): String?
 6→    fun ref(): String?
 7→}
 8→
 9→class ProcessGitInfoProvider : GitInfoProvider {
10→    override fun branch(): String? = runCatching { runGitCommand("rev-parse", "--abbrev-ref", "HEAD") }.getOrNull()
11→    override fun commitSha(): String? = runCatching { runGitCommand("rev-parse", "HEAD") }.getOrNull()
12→    override fun ref(): String? = runCatching { runGitCommand("describe", "--tags", "--always") }.getOrNull()
13→
14→    private fun runGitCommand(vararg args: String): String {
15→        val process = ProcessBuilder(listOf("git") + args)
16→            .redirectErrorStream(true)
17→            .start()
18→        try {
19→            val output = process.inputStream.bufferedReader().use { it.readLine()?.trim() }
20→            val exitCode = process.waitFor()
21→            if (exitCode != 0 || output.isNullOrBlank()) {
22→                throw RuntimeException("git ${args.first()} failed (exit code $exitCode)")
23→            }
24→            return output
25→        } catch (e: Exception) {
26→            process.destroyForcibly()
27→            throw e
28→        }
29→    }
30→}
