  1→function findNode(data, predicate) {
  2→  for (const node of data) {
  3→    if (predicate(node)) {
  4→      return node;
  5→    }
  6→    if (node.children) {
  7→      const found = findNode(node.children, predicate);
  8→      if (found) return found;
  9→    }
 10→  }
 11→  return null;
 12→}
