 14→export default {
 15→  mounted() {
 16→    const chart = document.querySelector(`#${this.el.dataset.chartId}`);
 17→
 18→    if (chart) {
 19→      const chartPart = chart.querySelector('[data-part="chart"]');
 20→      const element = chartPart || chart;
 21→      const chartContainer = element.closest(".noora-chart");
 22→
 23→      if (chartContainer && window.liveSocket && window.liveSocket.roots) {
 24→        for (const rootId in window.liveSocket.roots) {
 25→          const view = window.liveSocket.roots[rootId];
 26→          if (view && view.el && view.el.contains(chartContainer)) {
 27→            if (view.getHook) {
 28→              const hook = view.getHook(chartContainer);
 29→              if (hook && hook.chart) {
 30→                this.setupChartHandlers(hook.chart);
 31→                return;
 32→              }
 33→            }
 34→          }
 35→        }
 36→      }
 37→    }
 38→  },
 39→
 40→  setupChartHandlers(echart) {
 41→    this.handleBreadcrumbClicked = (event) => {
 42→      if (event.target.id == this.el.id && echart) {
 43→        const node = findNode(echart.getOption().series[0].data, (node) => node.id == event.detail.artifact_id);
 44→        if (node) {
 45→          echart.dispatchAction({
 46→            type: "sunburstRootToNode",
 47→            seriesIndex: 0,
 48→            targetNodeId: event.detail.artifact_id,
 49→          });
 50→          this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-selected-artifact", {
 51→            artifact: {
 52→              value: node.value,
 53→              name: node.name,
 54→              artifact_type: node.artifact_type,
 55→              artifact_id: node.artifact_id,
 56→              children: node.children || [],
 57→              path: node.path,
 58→            },
 59→          });
 60→        } else {
 61→          echart.dispatchAction({ type: "sunburstRootToNode", seriesIndex: 0, targetNode: "" });
 62→          this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-selected-root", {});
 63→        }
 64→      }
 65→    };
 66→    window.addEventListener("bundle-size-analysis-breadcrumb-clicked", this.handleBreadcrumbClicked);
 67→
 68→    this.handleTableRowClicked = (event) => {
 69→      if (event.target.id == this.el.id && echart) {
 70→        const artifact = event.detail.artifact;
 71→
 72→        if (artifact.artifact_type === "directory" || artifact.artifact_type === "asset") {
 73→          let node;
 74→          const seriesData = echart.getOption().series[0].data;
 75→
 76→          if (artifact.path) {
 77→            node = findNode(seriesData, (node) => node.path === artifact.path);
 78→          }
 79→
 80→          if (!node && artifact.artifact_id) {
 81→            node = findNode(seriesData, (node) => node.artifact_id === artifact.artifact_id);
 82→          }
 83→
 84→          if (node) {
 85→            echart.dispatchAction({
 86→              type: "sunburstRootToNode",
 87→              seriesIndex: 0,
 88→              targetNodeId: node.id,
 89→            });
 90→            this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-selected-artifact", {
 91→              artifact: {
 92→                value: node.value,
 93→                name: node.name,
 94→                artifact_type: node.artifact_type,
 95→                artifact_id: node.artifact_id,
 96→                children: node.children || [],
 97→                path: node.path,
 98→              },
 99→            });
100→          }
101→        } else {
102→          const seriesData = echart.getOption().series[0].data;
103→          const fileNode = findNode(seriesData, (node) => {
104→            return node.path === artifact.path;
105→          });
106→
107→          if (fileNode) {
108→            echart.dispatchAction({
109→              type: "highlight",
110→              seriesIndex: 0,
111→              name: artifact.name,
112→            });
113→          }
114→        }
115→      }
116→    };
117→    window.addEventListener("bundle-size-analysis-table-row-clicked", this.handleTableRowClicked);
118→
119→    let highlightedNewElement = false;
120→    this.handleOnHighlighted = (el) => {
121→      highlightedNewElement = true;
122→      if (el.name == "") {
123→        this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-highlighted-parent", {});
124→      } else if (el.data) {
125→        this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-highlighted-artifact", {
126→          artifact: {
127→            value: el.data.value,
128→            artifact_type: el.data.artifact_type,
129→            name: el.data.name,
130→            artifact_id: el.data.artifact_id,
131→            children: el.data.children || [],
132→            path: el.data.path,
133→          },
134→        });
135→      }
136→    };
137→
138→    echart.on("mouseover", this.handleOnHighlighted);
139→    echart.on("mouseout", (el) => {
140→      highlightedNewElement = false;
141→      setTimeout(() => {
142→        if (highlightedNewElement === false) {
143→          this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-no-highlighted-artifact", {});
144→        }
145→      }, 10);
146→    });
147→    echart.on("click", (params) => {
148→      if (params.name == "") {
149→        this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-selected-parent", {});
150→      } else if (params.data) {
151→        this.pushEvent("update-bundle-size-analysis-sunburst-chart-table-selected-artifact", {
152→          artifact: {
153→            value: params.data.value,
154→            name: params.data.name,
155→            artifact_type: params.data.artifact_type,
156→            artifact_id: params.data.artifact_id,
157→            children: params.data.children || [],
158→            path: params.data.path,
159→          },
160→        });
161→      }
162→    });
163→  },
164→
165→  destroyed() {
166→    if (this.handleBreadcrumbClicked) {
167→      window.removeEventListener("bundle-size-analysis-breadcrumb-clicked", this.handleBreadcrumbClicked);
168→    }
169→    if (this.handleTableRowClicked) {
