    private fun configureOpenTelemetryPlugin(
        project: Project,
        config: TuistGradleConfig,
        serviceProvider: org.gradle.api.provider.Provider<TuistBuildInsightsService>
    ) {
        project.plugins.withId("com.atkinsondev.opentelemetry-build") {
            try {
                val otelExtension = project.extensions.findByName("openTelemetryBuild")
                    ?: return@withId

                val configProvider = TuistCommandConfigurationProvider(
                    project = config.project,
                    command = listOf(config.executablePath),
                    url = config.url,
                    projectDir = project.rootDir
                )
                val tuistConfig = configProvider.getConfiguration()

                val accountHandle = tuistConfig.accountHandle
                val projectHandle = tuistConfig.projectHandle
                val baseUrl = config.url.trimEnd('/')
                val endpoint = "$baseUrl/api/projects/$accountHandle/$projectHandle/gradle/traces"

                val extensionClass = otelExtension.javaClass
                extensionClass.getMethod("setEndpoint", String::class.java).invoke(otelExtension, endpoint)
                extensionClass.getMethod("setExporterMode", String::class.java).invoke(otelExtension, "HTTP")
                extensionClass.getMethod("setHeaders", Map::class.java).invoke(
                    otelExtension,
                    mapOf("Authorization" to "Bearer ${tuistConfig.token}")
                )
                extensionClass.getMethod("setServiceName", String::class.java).invoke(
                    otelExtension,
                    project.rootProject.name
                )
                extensionClass.getMethod("setCustomTags", Map::class.java).invoke(
                    otelExtension,
                    mapOf("tuist.build.id" to serviceProvider.get().buildId)
                )

                logger.lifecycle("Tuist: OpenTelemetry build plugin auto-configured for $accountHandle/$projectHandle")
            } catch (e: Exception) {
                logger.warn("Tuist: Could not auto-configure OpenTelemetry build plugin: ${e.message}")
            }
        }
    }
}

