 48→    private let fileSystem: FileSysteming
 49→    /// This cache avoids having to traverse the directories hierarchy every time the locate method is called.
 50→    private let cache: ThreadSafe<[AbsolutePath: AbsolutePath]> = ThreadSafe([:])
 51→
