 59→        if let path = try await locate(from: path, source: path) {
 60→            return path
 61→        } else if try await fileSystem.exists(path, isDirectory: true), try await fileSystem.exists(
 62→            path.appending(component: Constants.SwiftPackageManager.packageSwiftName),
 63→            isDirectory: false
 64→        ) {
