 72→        if try await !fileSystem.exists(path, isDirectory: true) {
 73→            return try await locate(from: path.parentDirectory, source: source)
 74→        } else if let cachedDirectory = cached(path: path) {
 75→            return cachedDirectory
 76→        } else if try await fileSystem.exists(path.appending(component: Constants.tuistDirectoryName), isDirectory: true) {
 77→            cache(rootDirectory: path, for: source)
